// Mapear eventos de Instagram a formato Excel
const body = $input.first().json.body;
let mapped = {
  timestamp: new Date().toISOString(),
  event_type: '',
  user_id: '',
  username: '',
  text: '',
  comment_id: '',
  media_id: '',
  message_id: '',
  parent_id: '',
  media_type: '',
  sender_id: '',
  recipient_id: '',
  business_id: '' // Agregado para filtrar
};

// Verificar que sea evento de Instagram
if (body.object === 'instagram' && body.entry && body.entry.length > 0) {
  const entry = body.entry[0];

  // Extraer business_id del entry
  mapped.business_id = entry.id || '';

  // TIPO 1: Comments y Live Comments (estructura "changes")
  if (entry.changes && entry.changes.length > 0) {
    const change = entry.changes[0];
    const field = change.field;
    const value = change.value;

    if (field === 'comments') {
      mapped.event_type = 'comment';
      mapped.user_id = value.from?.id || '';
      mapped.username = value.from?.username || '';
      mapped.text = value.text || '';
      mapped.comment_id = value.id || '';
      mapped.parent_id = value.parent_id || '';
      mapped.media_id = value.media?.id || '';
      mapped.media_type = value.media?.media_product_type || '';

    } else if (field === 'live_comments') {
      mapped.event_type = 'live_comment';
      mapped.user_id = value.from?.id || '';
      mapped.username = value.from?.username || '';
      mapped.text = value.text || '';
      mapped.comment_id = value.id || '';
      mapped.media_id = value.media?.id || '';
      mapped.media_type = 'LIVE';
    }
  }

  // TIPO 2: Story Mentions (estructura "messaging")
  else if (entry.messaging && entry.messaging.length > 0) {
    const messaging = entry.messaging[0];

    // Verificar si es story_mention
    if (messaging.message?.attachments && messaging.message.attachments.length > 0) {
      const attachment = messaging.message.attachments[0];

      if (attachment.type === 'story_mention') {
        mapped.event_type = 'story_mention';
        mapped.sender_id = messaging.sender?.id || '';
        mapped.recipient_id = messaging.recipient?.id || '';
        mapped.timestamp = new Date(messaging.timestamp).toISOString();
        mapped.message_id = messaging.message?.mid || '';
        mapped.text = 'Story mention';
        mapped.media_type = 'STORY';
        mapped.user_id = messaging.sender?.id || '';

        // URL de la story si está disponible
        if (attachment.payload?.url) {
          mapped.media_id = attachment.payload.url;
        }
      }
    }
  }
}

return [{ json: mapped }];

const IG_USER_ID = "17841464586344140";
const ACCESS_TOKEN = "EAALtDCufaXkBQmx72pQyCOBZA4ZCMnZB4SGmZBut8lPlhT3Az9xyRxl0MbZAZC4fAIkeudMnlXbOzBNlG7uyMqfYuIQVvidXTZAqvmmqDuljGtWUynadlhkCA6w2qn9IKPTA6ABCNxI6X5J50YchZCZCSijq4StQj0D36zSziKO7hT7JZAe1oUgbgHe6kHt1WafAVQT6AoeFAc6TQyyesjkt8SvAZDZD";

const DAYS_BACK = 30; // Cambia a los días que necesites
const FILTER_BY_DATE = true; // Pon false para traer todo

const cutoffDate = new Date();
cutoffDate.setDate(cutoffDate.getDate() - DAYS_BACK);

let allTags = [];
let nextUrl = `https://graph.facebook.com/v24.0/${IG_USER_ID}/tags?fields=id,username,timestamp,permalink&limit=50&access_token=${ACCESS_TOKEN}`;
let pageCount = 0;
const MAX_PAGES = 10;

while (nextUrl && pageCount < MAX_PAGES) {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: nextUrl,
    json: true
  });

  if (response.error) {
    throw new Error(response.error.message);
  }

  let stopPagination = false;

  for (const tag of response.data || []) {
    // Solo filtrar si FILTER_BY_DATE es true
    if (FILTER_BY_DATE) {
      const tagDate = new Date(tag.timestamp);
      if (tagDate < cutoffDate) {
        stopPagination = true;
        break;
      }
    }

    allTags.push({
      id: tag.id,
      username: tag.username || "",
      timestamp: tag.timestamp,
      permalink: tag.permalink
    });
  }

  pageCount++;

  if (stopPagination) {
    break;
  }

  nextUrl = response.paging?.next || null;
}

return [{
  json: {
    tags: allTags,
    total_tags: allTags.length,
    pages_fetched: pageCount
  }
}];

// Tags del nodo anterior
const tagsData = $('Get All IG Tags').first().json.tags;

// Usuarios del Google Sheets
const sheetUsers = $('Search influencer').all();

const results = [];

for (const row of sheetUsers) {
  const username = (row.json.Username || "").toLowerCase().trim();

  // Filtrar tags de este usuario
  const userTags = tagsData.filter(tag => tag.username === username);

  results.push({
    json: {
      username: row.json.Username,
      email: row.json.Email,
      tags_count: userTags.length,
      last_tag_date: userTags.length > 0 ? userTags[0].timestamp : "",
      permalinks: userTags.map(t => t.permalink).join("\n")
    }
  });
}

return results;
